public class Main {
    public static void main(String[] args) {

        // Static input
        int[] arr = {1, 2, 2, 3, 4, 4, 4, 5, 5};

        int n = arr.length;

        System.out.print("[");

        for (int i = 0; i < n; i++) {
            // Print first element or if current is not equal to previous
            if (i == 0 || arr[i] != arr[i - 1]) {
                System.out.print(arr[i]);

                // Print comma if not the last element
                if (i < n - 1) {
                    System.out.print(", ");
                }
            }
        }

        System.out.print("]");
    }
}

